(function(){
'use strict';
var CAT_LABELS={company:'Company Info',services:'Services & Products',projects:'Projects',pricing:'Pricing',technical:'Technical Docs',faq:'FAQ',other:'Other'};

function kbAlert(msg,type){
    var el=document.getElementById('kbAlert');
    if(!el)return;
    el.className='alert alert-'+(type||'success')+' mb-3';
    el.textContent=msg;
    el.classList.remove('d-none');
    setTimeout(function(){el.classList.add('d-none');},4000);
}

function kbLoadDocs(){
    fetch('/customer_support/knowledge/list',{credentials:'same-origin',headers:{'Accept':'application/json'}})
    .then(function(r){return r.json();})
    .then(function(data){
        var docs=data.documents||[];
        document.getElementById('kbTotalDocs').textContent=docs.length;
        document.getElementById('kbReadyDocs').textContent=docs.filter(function(d){return d.state==='ready';}).length;
        document.getElementById('kbPendingDocs').textContent=docs.filter(function(d){return d.state==='pending';}).length;
        document.getElementById('kbErrorDocs').textContent=docs.filter(function(d){return d.state==='error';}).length;
        var tb=document.getElementById('kbDocsBody');
        if(!docs.length){
            tb.innerHTML='<tr><td colspan="7" class="text-center text-muted py-4"><i class="bi bi-folder2-open me-2"></i>No documents uploaded yet. Upload your first document above.</td></tr>';
            return;
        }
        tb.innerHTML=docs.map(function(d){
            var stateBadge=d.state==='ready'
                ?'<span class="badge bg-success">&#x2705; Ready</span>'
                :d.state==='error'
                ?'<span class="badge bg-danger" title="'+(d.error_msg||'')+'">&#x274C; Error</span>'
                :'<span class="badge bg-warning text-dark">&#x23F3; Pending</span>';
            var typeBadge={pdf:'<span class="badge bg-danger">PDF</span>',docx:'<span class="badge bg-primary">DOCX</span>',txt:'<span class="badge bg-success">TXT</span>',xlsx:'<span class="badge bg-info text-dark">XLSX</span>'}[d.file_type]||'<span class="badge bg-secondary">FILE</span>';
            return'<tr>'
                +'<td><strong>'+d.name+'</strong>'+(d.description?'<br><small class="text-muted">'+d.description+'</small>':'')+'</td>'
                +'<td><span class="badge bg-secondary">'+(CAT_LABELS[d.category]||d.category)+'</span></td>'
                +'<td>'+typeBadge+'</td>'
                +'<td>'+stateBadge+'</td>'
                +'<td class="text-center fw-bold text-primary">'+(d.chunk_count||0)+'</td>'
                +'<td><small class="text-muted">'+(d.create_date||'')+'</small></td>'
                +'<td><button class="btn btn-sm btn-outline-danger" onclick="kbDelete('+d.id+',\''+d.name.replace(/'/g,"\\'")+'\')" title="Delete"><i class="bi bi-trash3"></i></button></td>'
                +'</tr>';
        }).join('');
    })
    .catch(function(e){console.warn('KB load failed:',e);});
}

window.kbUpload=function(){
    var name=document.getElementById('kbDocName').value.trim();
    var category=document.getElementById('kbCategory').value;
    var desc=document.getElementById('kbDescription').value.trim();
    var fileEl=document.getElementById('kbFile');
    if(!name||!fileEl.files.length){kbAlert('Please fill in the document name and select a file.','warning');return;}
    var allowed=['.pdf','.docx','.txt','.xlsx'];
    var filename=fileEl.files[0].name.toLowerCase();
    if(!allowed.some(function(ext){return filename.endsWith(ext);})){kbAlert('Invalid file type. Allowed: PDF, DOCX, TXT, XLSX','danger');return;}
    var formData=new FormData();
    formData.append('name',name);
    formData.append('category',category);
    formData.append('description',desc);
    formData.append('file',fileEl.files[0]);
    var csrf=document.querySelector('input[name="csrf_token"]');
    if(csrf)formData.append('csrf_token',csrf.value);
    var btn=document.getElementById('kbUploadBtn');
    if(btn){btn.disabled=true;btn.innerHTML='<i class="bi bi-hourglass-split me-2"></i>Processing...';}
    fetch('/customer_support/knowledge/upload',{method:'POST',credentials:'same-origin',body:formData})
    .then(function(){
        kbAlert('Document uploaded and processed successfully! &#x2705;','success');
        document.getElementById('kbDocName').value='';
        document.getElementById('kbDescription').value='';
        document.getElementById('kbFile').value='';
        kbLoadDocs();
    })
    .catch(function(){kbAlert('Upload failed. Please try again.','danger');})
    .finally(function(){if(btn){btn.disabled=false;btn.innerHTML='<i class="bi bi-upload me-2"></i>Upload &amp; Process';}});
};

window.kbDelete=function(id,name){
    if(!confirm('Delete "'+name+'"?\nThe AI will no longer use this document.'))return;
    var formData=new FormData();
    var csrf=document.querySelector('input[name="csrf_token"]');
    if(csrf)formData.append('csrf_token',csrf.value);
    fetch('/customer_support/knowledge/delete/'+id,{method:'POST',credentials:'same-origin',body:formData})
    .then(function(){kbAlert('Document deleted.','success');kbLoadDocs();})
    .catch(function(){kbAlert('Delete failed.','danger');});
};

document.addEventListener('DOMContentLoaded',function(){
    var modal=document.getElementById('knowledgeBaseModal');
    if(modal)modal.addEventListener('shown.bs.modal',function(){kbLoadDocs();});
});
})();
